mapper.select:
select fh.*, fc.name as carrierName, u.username as creatorName, date_format(fh.bill_time, '%Y-%m-%d') as billTimeStr, u2.username as paymentOperatorName, date_format(fh.payment_time, '%Y-%m-%d %H:%i') as paymentTimeStr, (select GROUP_CONCAT(DISTINCT dh2.number SEPARATOR ', ') from jsh_freight_item fi2 left join jsh_depot_head dh2 on fi2.depot_head_id = dh2.id where fi2.header_id = fh.id and fi2.delete_flag = '0') as saleOutNumbers, (select GROUP_CONCAT(DISTINCT s2.supplier SEPARATOR ', ') from jsh_freight_item fi3 left join jsh_depot_head dh3 on fi3.depot_head_id = dh3.id left join jsh_supplier s2 on dh3.organ_id = s2.id and ifnull(s2.delete_flag,'0') != '1' where fi3.header_id = fh.id and fi3.delete_flag = '0') as customerNames, (select GROUP_CONCAT(DISTINCT s4.project_name SEPARATOR ', ') from jsh_freight_item fi4 left join jsh_depot_head dh4 on fi4.depot_head_id = dh4.id left join jsh_supplier s4 on dh4.organ_id = s4.id and ifnull(s4.delete_flag,'0') != '1' where fi4.header_id = fh.id and fi4.delete_flag = '0' and s4.project_name is not null and s4.project_name != '') as projectNames from jsh_freight_head fh left join jsh_freight_carrier fc on fh.carrier_id = fc.id left join jsh_user u on fh.creator = u.id left join jsh_user u2 on fh.payment_operator = u2.id where fh.delete_flag = '0'
and fh.bill_no like #{bindBillNo}
and fh.carrier_id = #{carrierId}
and fh.status = #{status}
and ifnull(fh.payment_status, '0') = #{paymentStatus}
and ifnull(fh.delivery_status, '0') = #{deliveryStatus}
and fh.bill_time >= #{beginTime}
and fh.bill_time <= #{endTime}
order by fh.id desc

